// Récupérer les données du webhook
const webhookData = $input.first().json.body;
const messageData = webhookData.data.messages;
const message = messageData.message;

// Détecter le type de message
let messageType = 'unknown';
let content = null;
let mediaInfo = null;

// Vérifier chaque type possible
if (message.conversation || message.extendedTextMessage) {
  messageType = 'text';
  content = message.conversation || message.extendedTextMessage?.text;
} 
else if (message.imageMessage) {
  messageType = 'image';
  content = message.imageMessage.caption || '';
  mediaInfo = {
    url: message.imageMessage.url,
    mimetype: message.imageMessage.mimetype,
    mediaKey: message.imageMessage.mediaKey,
    fileSha256: message.imageMessage.fileSha256
  };
}
else if (message.videoMessage) {
  messageType = 'video';
  content = message.videoMessage.caption || '';
  mediaInfo = {
    url: message.videoMessage.url,
    mimetype: message.videoMessage.mimetype,
    mediaKey: message.videoMessage.mediaKey
  };
}
else if (message.audioMessage) {
  messageType = 'audio';
  mediaInfo = {
    url: message.audioMessage.url,
    mimetype: message.audioMessage.mimetype,
    mediaKey: message.audioMessage.mediaKey,
    ptt: message.audioMessage.ptt // true si c'est un message vocal (push-to-talk)
  };
}
else if (message.documentMessage) {
  messageType = 'document';
  content = message.documentMessage.caption || '';
  mediaInfo = {
    url: message.documentMessage.url,
    fileName: message.documentMessage.fileName,
    mimetype: message.documentMessage.mimetype,
    mediaKey: message.documentMessage.mediaKey
  };
}
else if (message.stickerMessage) {
  messageType = 'sticker';
  mediaInfo = {
    url: message.stickerMessage.url,
    mediaKey: message.stickerMessage.mediaKey
  };
}
else if (message.contactMessage) {
  messageType = 'contact';
  content = message.contactMessage.displayName;
}
else if (message.locationMessage) {
  messageType = 'location';
  content = `Lat: ${message.locationMessage.degreesLatitude}, Long: ${message.locationMessage.degreesLongitude}`;
}

// Retourner les données structurées
return {
  json: {
    event: webhookData.event,
    timestamp: webhookData.timestamp,
    messageId: messageData.key.id,
    from: messageData.key.remoteJid.replace('@s.whatsapp.net', ''),
    fromMe: messageData.key.fromMe,
    messageType: messageType,
    text: content,
    mediaInfo: mediaInfo,
    // Données brutes pour débogage
    rawMessage: message
  }
};
